// Agrupa mensajes por threadId y arma upsert para gmail_hilos.
// Estado: si el ÚLTIMO mensaje del hilo lo mandó Blas -> respondido_por_nos; si no -> esperando_respuesta.
// Tag de prioridad por dominio: @uflouniversidad.edu.ar es alta.
const me = 'blas.rivera@uflouniversidad.edu.ar';
const items = $input.all();
const byThread = new Map();
for (const item of items) {
  const m = item.json;
  const tid = m.threadId || m.id;
  if (!tid) continue;
  const headers = (m.payload?.headers || []).reduce((acc,h)=>{ acc[h.name.toLowerCase()] = h.value; return acc; }, {});
  const from = headers['from'] || '';
  const to = headers['to'] || '';
  const subject = headers['subject'] || '(sin asunto)';
  const dateMs = parseInt(m.internalDate || '0', 10) || Date.parse(headers['date'] || '') || Date.now();
  const fromEmail = (from.match(/<([^>]+)>/) || [, from])[1].toLowerCase().trim();
  const fromMe = fromEmail.includes(me.toLowerCase());
  const existing = byThread.get(tid);
  if (!existing || dateMs > existing.last_ms) {
    byThread.set(tid, {
      thread_id: tid,
      asunto: subject.replace(/^(Re:|Fwd:|RE:|FW:)\s*/i, ''),
      ultimo_mensaje_at: new Date(dateMs).toISOString(),
      ultimo_mensaje_de: from,
      from_email: fromEmail,
      from_me: fromMe,
      last_ms: dateMs,
      participantes: existing?.participantes || new Set(),
      mensajes: existing?.mensajes || []
    });
  }
  const t = byThread.get(tid);
  t.participantes.add(fromEmail);
  if (to) for (const e of to.split(',')) t.participantes.add(e.trim().toLowerCase());
  t.mensajes.push({ from, subject, snippet: m.snippet || '', date: new Date(dateMs).toISOString() });
  if (!t.primer_mensaje_at || dateMs < Date.parse(t.primer_mensaje_at)) t.primer_mensaje_at = new Date(dateMs).toISOString();
}
const out = [];
for (const t of byThread.values()) {
  const estado = t.from_me ? 'respondido_por_nos' : 'esperando_respuesta';
  const uflo = t.from_email.endsWith('@uflouniversidad.edu.ar') || [...t.participantes].some(p => p.endsWith('@uflouniversidad.edu.ar'));
  out.push({ json: {
    thread_id: t.thread_id,
    asunto: t.asunto,
    participantes: [...t.participantes],
    primer_mensaje_at: t.primer_mensaje_at || t.ultimo_mensaje_at,
    ultimo_mensaje_at: t.ultimo_mensaje_at,
    ultimo_mensaje_de: t.ultimo_mensaje_de,
    estado,
    clasificacion: uflo ? 'uflo_interno' : 'externo',
    raw_mensajes: t.mensajes.slice(-5)
  } });
}
return out;
